use typed_arena::Arena;
use std::collections::HashMap;

#[derive(Debug, Clone)]
struct NodeIdentifier {
    label: String,
    index: usize,
}

#[derive(Debug, Clone)]
enum GraphOperation {
    MatchNode(NodeIdentifier),
    And(Box<GraphOperation>, Box<GraphOperation>),
    DepthLimit(Box<GraphOperation>, usize),
}

struct ASTBuilder {
    arena: Arena<GraphOperation>,
    node_map: HashMap<String, NodeIdentifier>,
}

impl ASTBuilder {
    fn new() -> Self {
        ASTBuilder {
            arena: Arena::new(),
            node_map: HashMap::new(),
        }
    }

    fn register_node(&mut self, label: &str, index: usize) -> NodeIdentifier {
        let id = NodeIdentifier { label: label.to_string(), index };
        self.node_map.insert(label.to_string(), id.clone());
        id
    }

    fn build_ast(&mut self, input_query: &str) -> Option<Box<GraphOperation>> {
        if input_query.is_empty() {
            return None;
        }

        let parts: Vec<&str> = input_query.split(" AND ").collect();
        if parts.len() == 1 {
            // Simplistic parsing for a single operation
            if let Some(depth) = input_query.find("DEPTH=") {
                let sub_str = &input_query[..];
                let limit_val: usize = sub_str.split(":d+").last().unwrap_or(&"0").trim().parse().unwrap_or(0);
                let base_op = Box::new(GraphOperation::MatchNode(self.register_node("Start", 1)));
                Some(Box::new(GraphOperation::DepthLimit(base_op, limit_val))) 
            } else {
                 Some(Box::new(GraphOperation::MatchNode(self.register_node("Start", 1))))
            }
        } else {
            // Conjunction logic (AND)
            let mut current_and: Option<Box<GraphOperation>> = None;
            for i in 0..parts.len() { 
                let part = parts[i];
                if let Some(op) = self.parse_part(part) {
                    match &mut current_and {
                        None => current_and = Some(op),
                        Some(base) => {
                            let new_and = Box::new(GraphOperation::And(base.clone(), op));
                            current_and = Some(new_and);
                        }
                    }
                }
            }
            current_and
        }
    }

    fn parse_part(&mut self, part: &str) -> Option<Box<GraphOperation>> {
         if part.contains("DEPTH=") {
             let limit_val: usize = part.split(":d+").last().unwrap_or(&"0").trim().parse().unwrap_or(0);
             let base_op = Box::new(GraphOperation::MatchNode(self.register_node("Start", 1)));
             return Some(Box::new(GraphOperation::DepthLimit(base_op, limit_val)));
         } else {
             // Assume simple node match for other parts
             let id = self.register_node("Start", 1);
             Some(Box::new(GraphOperation::MatchNode(id))) 
         }
    }
}

fn main() {
    let mut builder = ASTBuilder::new();
    let query = "MATCH(a:Person) AND a.knows > 1 DEPTH=3";
